            var columnFiredTime = new DataColumn("FiredTime", typeof(DateTime));
            columnFiredTime.AllowDBNull = false;
            table.Columns.Add(columnFiredTime);

            return table;
        }

        public static void SaveEntity2DataTable(DataTable table, BvHistoryDeltaEntity entity)
        {
            var rowData = new object[]
                {
                    entity.ID,
                    entity.SurveyId,
                    entity.PersonId,
                    entity.ITS,
                    entity.LogonTime,
                    entity.WaitingTime,
                    entity.FiredTime
                };

            table.Rows.Add(rowData);
        }
    }
}
